import React, { useState } from "react";
import axios from "axios";
import Swal from "sweetalert2";
import { XMarkIcon } from "@heroicons/react/24/solid";

export default function EditProfile({ user, closeModal, onUpdated }) {
  const [name, setName] = useState(user?.name || "");
  const [imageFile, setImageFile] = useState(null);
  const [preview, setPreview] = useState(user?.profileImage || "");

  const [currentPassword, setCurrentPassword] = useState("");
  const [newPassword, setNewPassword] = useState("");

  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    setImageFile(file);
    const reader = new FileReader();
    reader.onloadend = () => setPreview(reader.result);
    reader.readAsDataURL(file);
  };

  const handleUpdateProfile = async () => {
    try {
      const formData = new FormData();
      formData.append("email", user.email);
      formData.append("name", name);

      if (imageFile) formData.append("image", imageFile);

      const res = await axios.put(
        "http://localhost:8086/user/update-profile",
        formData
      );

      Swal.fire("Success", "Profile updated", "success");

      localStorage.setItem("user", JSON.stringify(res.data));
      onUpdated(res.data);
      closeModal();
    } catch (err) {
      Swal.fire("Error", "Update failed", "error");
    }
  };

  const handleChangePassword = async () => {
    try {
      const res = await axios.put(
        "http://localhost:8086/user/change-password",
        {
          email: user.email,
          currentPassword,
          newPassword,
        }
      );

      Swal.fire("Success", res.data.message, "success");
      setCurrentPassword("");
      setNewPassword("");
    } catch (err) {
      Swal.fire("Error", "Password update failed", "error");
    }
  };

  return (
    <div className="fixed inset-0 flex items-center justify-center z-50">

      {/* BACKDROP */}
      <div
        className="absolute inset-0 bg-black/50 backdrop-blur-md"
        onClick={closeModal}
      />

      {/* MODAL */}
      <div className="relative w-[900px] max-w-[95%] rounded-3xl bg-white/10 backdrop-blur-2xl border border-white/20 shadow-2xl overflow-hidden">

        {/* HEADER */}
        <div className="flex items-center justify-between px-6 py-4 border-b border-white/10">
          <h2 className="text-white text-lg font-semibold">
            ✨ Edit Profile
          </h2>

          <button
            onClick={closeModal}
            className="text-white/70 hover:text-red-400 transition"
          >
            <XMarkIcon className="w-6 h-6" />
          </button>
        </div>

        {/* BODY */}
        <div className="grid grid-cols-2 gap-6 p-6">

          {/* LEFT - PROFILE */}
          <div className="bg-white/10 rounded-2xl p-5 border border-white/10">
            <h3 className="text-white font-semibold mb-4">Profile Info</h3>

            {/* IMAGE */}
            <div className="flex flex-col items-center">
              <div className="relative">
                <img
                  src={preview}
                  className="w-28 h-28 rounded-full border-4 border-white/30 object-cover"
                  alt="profile"
                />
              </div>

              <label className="mt-3 cursor-pointer text-sm text-white/70 hover:text-white">
                Change Photo
                <input
                  type="file"
                  onChange={handleImageChange}
                  className="hidden"
                />
              </label>
            </div>

            {/* NAME */}
            <div className="mt-5">
              <label className="text-white/70 text-sm">Name</label>
              <input
                value={name}
                onChange={(e) => setName(e.target.value)}
                className="w-full mt-1 p-3 rounded-xl bg-white/10 text-white border border-white/20 outline-none focus:border-indigo-400"
                placeholder="Your name"
              />
            </div>

            {/* SAVE */}
            <button
              onClick={handleUpdateProfile}
              className="w-full mt-5 py-3 rounded-xl bg-gradient-to-r from-indigo-500 to-purple-500 text-white font-semibold hover:opacity-90 transition"
            >
              Save Changes
            </button>
          </div>

          {/* RIGHT - PASSWORD */}
          <div className="bg-white/10 rounded-2xl p-5 border border-white/10">
            <h3 className="text-white font-semibold mb-4">Security</h3>

            <div className="space-y-3">
              <div>
                <label className="text-white/70 text-sm">
                  Current Password
                </label>
                <input
                  type="password"
                  value={currentPassword}
                  onChange={(e) => setCurrentPassword(e.target.value)}
                  className="w-full mt-1 p-3 rounded-xl bg-white/10 text-white border border-white/20 outline-none focus:border-purple-400"
                />
              </div>

              <div>
                <label className="text-white/70 text-sm">
                  New Password
                </label>
                <input
                  type="password"
                  value={newPassword}
                  onChange={(e) => setNewPassword(e.target.value)}
                  className="w-full mt-1 p-3 rounded-xl bg-white/10 text-white border border-white/20 outline-none focus:border-purple-400"
                />
              </div>

              <button
                onClick={handleChangePassword}
                className="w-full mt-4 py-3 rounded-xl bg-gradient-to-r from-pink-500 to-purple-500 text-white font-semibold hover:opacity-90 transition"
              >
                Update Password
              </button>
            </div>

            {/* TIP */}
            <p className="text-xs text-white/40 mt-4">
              Use a strong password for better security.
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}
